import pandas as pd

def load_orders():
    df = pd.DataFrame({
        'order_id': [1, 2, 3, 4],
        'price':    [10.0, 25.5, 7.99, 100.0],
        'region':   ['EU', 'US', 'EU', 'US'],
        'tier':     ['gold', 'silver', 'silver', 'gold'],
    })
    # Pivot into a "hierarchical" schema with top-level groups
    df.columns = pd.MultiIndex.from_tuples([
        ('fact', 'order_id'),
        ('fact', 'price'),
        ('meta', 'region'),
        ('meta', 'tier'),
    ])
    return df

def load_customers():
    # Flat columns
    return pd.DataFrame({'order_id': [1, 2, 3, 4], 'cust': ['a','b','a','c']})

def monthly_revenue():
    orders = load_orders()
    custs = load_customers()
    # BUG: merging a MultiIndex-column frame with a flat one flattens the
    # columns to a single level of tuples like "('fact','order_id')" string,
    # so ('meta','region') is no longer a valid key.
    joined = orders.merge(custs, left_on=('fact','order_id'), right_on='order_id')
    try:
        by_region = joined.groupby([('meta','region'), ('meta','tier')])['price'].sum()
    except KeyError as e:
        raise RuntimeError(f"failed to aggregate: {e}") from e
    return by_region

if __name__ == '__main__':
    print(monthly_revenue())
